import { ChatFlow } from 'flowise-components';

const detectSchemaDrift = (flow: ChatFlow, executionData: any) => {
  const llmChainNodes = flow.nodes.filter(n => n.type === 'llm-chain');
  const violations: string[] = [];

  llmChainNodes.forEach(node => {
    const output = executionData[node.id]?.output;
    if (output && typeof output === 'string') {
      try {
        const parsed = JSON.parse(output);
        // Expected schema for this node type
        if (!parsed.result || typeof parsed.result !== 'string') {
          violations.push(`Node ${node.id}: Missing 'result' field`);
        }
      } catch (e) {
        violations.push(`Node ${node.id}: Invalid JSON output`);
      }
    }
  });

  return {
    hasIssues: violations.length > 0,
    details: violations
  };
};
