const detectPoorRetrieval = (executionData: any) => {
  const retrieverNodes = Object.keys(executionData).filter(k => 
    k.includes('retriever') || k.includes('vectorstore')
  );

  const lowRelevance: any[] = [];

  retrieverNodes.forEach(nodeId => {
    const nodeData = executionData[nodeId];
    if (nodeData?.documents && nodeData.metadata) {
      const avgSimilarity = nodeData.metadata
        .map((m: any) => m.similarity || 0)
        .reduce((a: number, b: number) => a + b, 0) / nodeData.metadata.length;

      if (avgSimilarity < 0.75) {
        lowRelevance.push({
          nodeId,
          avgSimilarity,
          docCount: nodeData.documents.length
        });
      }
    }
  });

  return {
    hasIssues: lowRelevance.length > 0,
    metrics: lowRelevance
  };
};
