const detectContextLoss = (flow: ChatFlow, chatHistory: any[]) => {
  const memoryNodes = flow.nodes.filter(n => 
    n.type.includes('memory') || n.type.includes('buffer')
  );

  if (chatHistory.length < 2) return { hasIssues: false };

  const recentMessages = chatHistory.slice(-5);
  const contextReferences = recentMessages.filter(msg => 
    msg.content.includes('previous') || msg.content.includes('earlier')
  );

  const issues = [];
  if (contextReferences.length === 0 && chatHistory.length > 3) {
    issues.push('No context references in multi-turn conversation');
  }

  return {
    hasIssues: issues.length > 0,
    details: issues,
    contextRetentionRate: contextReferences.length / recentMessages.length
  };
};
