import { INode, FlowiseConfig } from 'flowise-components';

const addOutputValidation = (flow: INode[]) => {
  flow.forEach(node => {
    if (node.type === 'llm-chain' || node.type === 'agent-executor') {
      // Insert Output Parser after LLM nodes
      node.edges?.forEach(edge => {
        if (!edge.target.includes('parser')) {
          const parserNode = {
            id: `${node.id}-parser`,
            type: 'output-parser',
            data: {
              schema: node.data?.outputSchema || '{ "result": "string" }',
              errorHandling: 'retry'
            }
          };
          flow.push(parserNode);
          edge.target = parserNode.id;
        }
      });
    }
  });
  return flow;
};
