import { Vex } from '@vex_dev/sdk';
import { ChatFlowRunner } from 'flowise-components';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY!
});

const flowiseCallback = async (data: any) => {
  // Monitor all node outputs for consistency
  await vex.capture('flowise_execution', {
    flowId: data.flowId,
    nodeOutputs: data.nodeOutputs,
    similarities: data.retrieval?.metadata,
    memoryState: data.memory,
    finalOutput: data.output
  });

  // Auto-detect issues
  const issues = await vex.check({
    testId: 'output_consistency',
    metrics: {
      jsonParseSuccess: data.stats?.parseSuccessRate || 0,
      avgSimilarity: data.stats?.avgSimilarity || 0,
      toolSuccessRate: data.stats?.toolSuccess || 0
    }
  });

  if (issues.length > 0) {
    await vex.autofix('flowise_agent_consistency', {
      flowConfig: data.flowConfig,
      detectedIssues: issues
    });
  }
};

// Register in Flowise
const runner = new ChatFlowRunner();
runner.addCallback('execution_complete', flowiseCallback);
